  const ticketId = existingTicketId || newTicketId;
  const category = $('Parse Agent Response').first().json.category;
  const priority = $('Parse Agent Response').first().json.priority;
  const channelId = $('Parse Agent Response').first().json.channel_id;
  const threadTs = $('Parse Agent Response').first().json.thread_ts;

  const blocks = [
    { type: 'section', text: { type: 'mrkdwn', text: ':bust_in_silhouette: *人事AI回答*' } },
    { type: 'section', text: { type: 'mrkdwn', text: aiText } },
    { type: 'divider' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: ':ticket: チケット: `' + ticketId + '` | :label: ' + category + ' | :zap: ' + priority }] },
    { type: 'section', text: { type: 'mrkdwn', text: 'この回答は役に立ちましたか？' } }
  ];

  const actionElements = [
    { type: 'button', text: { type: 'plain_text', text: '✅ 解決しました' }, style: 'primary', action_id: 'resolved', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'hr' }) },
    { type: 'button', text: { type: 'plain_text', text: '📝 有人対応依頼' }, action_id: 'direct_ticket', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'hr' }) },
